(32, 1, 'Контакты', '', 3, '<link rel="stylesheet" href="/assets/sfera/css/contact.css">\r\n<!-- Main Content -->\r\n<main class="contact-page">\r\n    <div class="container">\r\n        <div class="page-header">\r\n            <h1>Контакты</h1>\r\n        </div>\r\n\r\n        <!-- Яндекс.Карта -->\r\n        <div class="map-wrapper">\r\n            <script type="text/javascript" charset="utf-8" async src="https://api-maps.yandex.ru/services/constructor/1.0/js/?um=constructor%3A121690b3d596abcf8d130c13d6d1d9b6fcf61175ff348ecfbd5d311618e057e5&amp;width=100%25&amp;height=500&amp;lang=ru_RU&amp;scroll=true"></script>\r\n        </div>\r\n\r\n        <!-- Контактная информация -->\r\n        <div class="contact-info-grid">\r\n\r\n            <!-- Отдел продаж -->\r\n            <div class="contact-block">\r\n                <h2>Отдел оптовых и розничных продаж</h2>\r\n                <div class="contact-item">\r\n                    <strong>Адрес:</strong> 129323, Москва, Лазоревый пр-д, д.3 (м. Ботанический сад).\r\n                </div>\r\n                <div class="contact-item">\r\n                    <strong>Телефоны:</strong>\r\n                    <a href="tel:+74956567505">+7 (495) 656-75-05</a>,\r\n                    <a href="tel:+74956567205">+7 (495) 656-72-05</a>\r\n                </div>\r\n                <div class="contact-item">\r\n                    <strong>E-mail:</strong> <a href="mailto:sfera@tc-sfera.ru">sfera@tc-sfera.ru</a>\r\n                </div>\r\n            </div>\r\n\r\n            <!-- Издательский отдел -->\r\n            <div class="contact-block">\r\n                <h2>Издательский отдел</h2>\r\n                <div class="contact-item">\r\n                    <strong>Адрес:</strong> 129226, Москва, ул. Сельскохозяйственная, д. 18, корп. 3 (м. Ботанический сад).\r\n                </div>\r\n                <div class="contact-item">\r\n                    <strong>Телефоны:</strong>\r\n                    <a href="tel:+74956567033">+7 (495) 656-70-33</a>,\r\n                    <a href="tel:+74956567300">+7 (495) 656-73-00</a>\r\n                </div>\r\n                <div class="contact-item">\r\n                    <strong>E-mail:</strong> <a href="mailto:dou@tc-sfera.ru">dou@tc-sfera.ru</a>\r\n                </div>\r\n            </div>\r\n\r\n        </div>\r\n    </div>\r\n</main>', 2, '2025-12-11 12:19:39', '2025-12-11 13:34:46');